const TRANSIT_KNOWLEDGE: Record<string, { lines: string[], trainLines?: string[] }> = {
  'paulista': { 
    lines: ['809U-10', '709P-10', '6414-10'], 
    trainLines: ['Linha 9-Esmeralda', 'Linha 4-Amarela'] 
  },
  'se_cathedral': { 
    lines: ['6451-10', '5111-10'], 
    trainLines: ['Linha 9-Esmeralda', 'Linha 1-Azul'] 
  },
  'ibirapuera': { 
    lines: ['5154-10', '6414-10', '6412-10'], 
    trainLines: ['Linha 9-Esmeralda', 'Linha 5-Lilás'] 
  },
  'masp': { 
    lines: ['809U-10', '669A-10'], 
    trainLines: ['Linha 4-Amarela', 'Linha 2-Verde'] 
  },
  'mercadão': { 
    lines: ['6451-10', '6450-10'], 
    trainLines: ['Linha 9-Esmeralda', 'Expresso Tiradentes'] 
  },
  'casa_christina': {
    lines: ['746C-10', '746P-10', '807M-10'],
